mapper.update:
UPDATE research_task
SET stage = #{stage}, heartbeat_at = #{now}, lease_until = #{leaseUntil}, updated_at = #{now}
WHERE id = #{taskId} AND status = 'RUNNING' AND lease_owner = #{leaseOwner}

UPDATE research_task
SET status = #{status}, stage = #{stage}, last_error = #{error},
    heartbeat_at = #{now}, lease_owner = NULL, lease_until = NULL, updated_at = #{now}
WHERE id = #{taskId}

UPDATE research_task
SET status = 'RETRYING', stage = 'RETRYING', lease_owner = NULL, lease_until = NULL, updated_at = #{now}
WHERE id = #{taskId} AND status = #{expectedStatus} AND attempt_count < 3

UPDATE research_task
SET status = 'RETRYING', stage = 'RETRYING', lease_owner = NULL, lease_until = NULL, updated_at = #{now}
WHERE id = #{taskId}
  AND status = 'RUNNING'
  AND attempt_count < 3
  AND COALESCE(heartbeat_at, updated_at) < #{heartbeatBefore}

mapper.select:
SELECT id, thread_id, query, search_mode, status, revision_number, created_at, updated_at
FROM research_task

    owner_id = #{ownerId}
    AND status = #{status}

        AND (query LIKE CONCAT('%', #{keyword}, '%') OR thread_id LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY updated_at DESC, id DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM research_task

    owner_id = #{ownerId}
    AND status = #{status}

        AND (query LIKE CONCAT('%', #{keyword}, '%') OR thread_id LIKE CONCAT('%', #{keyword}, '%'))

SELECT id, thread_id, query, search_mode, status, revision_number, created_at, updated_at
FROM research_task
WHERE owner_id = #{ownerId} AND id = #{taskId}
